import { Button } from '@/components/ui/button';import type { SupplierContact } from '../types';
export const ContactTable=({contacts,isLoading,onEdit,onDelete,onPrimary,onEmergency,showSupplier=true}:{contacts:SupplierContact[];isLoading:boolean;onEdit?:(x:SupplierContact)=>void;onDelete?:(x:SupplierContact)=>void;onPrimary?:(x:SupplierContact)=>void;onEmergency?:(x:SupplierContact)=>void;showSupplier?:boolean})=>{if(isLoading)return <div className="space-y-3 p-5">{Array.from({length:5}).map((_,i)=><div key={i} className="h-12 animate-pulse rounded bg-slate-100 dark:bg-slate-800"/>)}</div>;if(!contacts.length)return <p className="p-10 text-center text-sm text-slate-500">No supplier contacts found.</p>;return <div className="overflow-x-auto"><table className="min-w-full text-left text-sm"><thead className="border-b bg-slate-50 text-xs uppercase text-slate-500 dark:border-slate-700 dark:bg-slate-800"><tr>{showSupplier?<th className="px-4 py-3">Supplier</th>:null}<th className="px-4 py-3">Contact</th><th className="px-4 py-3">Department</th><th className="px-4 py-3">Phone / Email</th><th className="px-4 py-3">Type</th><th className="px-4 py-3">Actions</th></tr></thead><tbody className="divide-y dark:divide-slate-800">{contacts.map(c=><tr key={c.id}>{showSupplier?<td className="px-4 py-3 font-semibold">{c.supplier_name}</td>:null}<td className="px-4 py-3"><p className="font-semibold">{c.name}</p><p className="text-xs text-slate-400">{c.job_title||''}</p></td><td className="px-4 py-3 text-slate-600 dark:text-slate-300">{c.department||'—'}</td><td className="px-4 py-3"><p>{c.phone||'—'}</p><p className="text-xs text-slate-400">{c.email||''}</p></td><td className="px-4 py-3"><div className="flex gap-1">{(c.is_primary===true||c.is_primary===1)?<span className="rounded-full bg-indigo-100 px-2 py-1 text-xs text-indigo-700">Primary</span>:null}{(c.is_emergency===true||c.is_emergency===1)?<span className="rounded-full bg-red-100 px-2 py-1 text-xs text-red-700">Emergency</span>:null}</div></td><td className="px-4 py-3"><div className="flex flex-wrap gap-1">{onEdit?<Button size="sm" variant="ghost" onClick={()=>onEdit(c)}>Edit</Button>:null}{onPrimary&&!(c.is_primary===true||c.is_primary===1)?<Button size="sm" variant="ghost" onClick={()=>onPrimary(c)}>Make primary</Button>:null}{onEmergency&&!(c.is_emergency===true||c.is_emergency===1)?<Button size="sm" variant="ghost" onClick={()=>onEmergency(c)}>Emergency</Button>:null}{onDelete?<Button size="sm" variant="ghost" className="text-red-600" onClick={()=>onDelete(c)}>Remove</Button>:null}</div></td></tr>)}</tbody></table></div>;};
